import{_ as o,o as t,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"179. Public Holidays","description":"","frontmatter":{"title":"179. Public Holidays","eba":"Mental Health Services 2024-2028","topics":["leave","public-holidays","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/179-public-holidays.md","filePath":"ebas/mental-health/support-services/preliminary/179-public-holidays.md"}'),n={name:"ebas/mental-health/support-services/preliminary/179-public-holidays.md"};function s(l,e,i,p,h,d){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_179-public-holidays" tabindex="-1">179. Public Holidays <a class="header-anchor" href="#_179-public-holidays" aria-label="Permalink to &quot;179. Public Holidays&quot;">​</a></h1><p><strong>179.1</strong> Entitlement to be absent on a public holiday</p><p><strong>(a)</strong> An Employee is entitled to be absent from their employment on a day or part-day that is a public holiday in the place where the Employee is based for work purposes.</p><p><strong>(b)</strong> However, an Employer may request an Employee to work on a public holiday if the request is reasonable.</p><p><strong>(c)</strong> If an Employer requests an Employee to work on a public holiday, the Employee may refuse the request if:</p><p><strong>(i)</strong> the request is not reasonable; or</p><p><strong>(ii)</strong> the refusal is reasonable.</p><p><strong>(d)</strong> In determining whether a request, or a refusal of a request, to work on a public holiday is reasonable, the following must be taken into account:</p><p><strong>(i)</strong> the nature of the Employer’s workplace or enterprise (including its operational requirements), and the nature of the work performed by the Employee</p><p><strong>(ii)</strong> the Employee’s personal circumstances, including family responsibilities</p><p><strong>(iii)</strong> whether the Employee could reasonably expect that the Employer might request work on the public holiday</p><p><strong>(iv)</strong> whether the Employee is entitled to receive overtime payments, penalty rates or other compensation for, or a level of remuneration that reflects an expectation of, work on the public holiday</p><p><strong>(v)</strong> the type of employment of the Employee (for example, whether full- time, part-time, casual or shiftwork)</p><p><strong>(vi)</strong> the amount of notice in advance of the public holiday given by the Employer when making the request</p><p><strong>(vii)</strong> in relation to the refusal of a request – the amount of notice in advance of the public holiday given by the Employee when refusing the request; and</p><p><strong>(viii)</strong> any other relevant matter.</p><p><strong>179.2</strong> Meaning of public holiday Employees shall be entitled to the following public holidays:</p><p><strong>(a)</strong> 1 January (New Year’s Day)</p><p><strong>(b)</strong> 26 January (Australia Day)</p><p><strong>(c)</strong> Labour Day</p><p><strong>(d)</strong> Good Friday</p><p><strong>(e)</strong> Easter Saturday</p><p><strong>(f)</strong> Easter Sunday</p><p><strong>(g)</strong> Easter Monday</p><p><strong>(h)</strong> 25 April (ANZAC Day)</p><p><strong>(i)</strong> King&#39;s Birthday</p><p><strong>(j)</strong> the Friday before the AFL Grand Final</p><p><strong>(k)</strong> Melbourne Cup Day</p><p><strong>(l)</strong> 25 December (Christmas Day)</p><p><strong>(m)</strong> 26 December (Boxing Day)</p><p><strong>179.3</strong> Additional / Substitute Days</p><p><strong>(a)</strong> When Christmas Day falls on a Saturday or Sunday, a holiday in lieu thereof shall be observed on 27 December.</p><p><strong>(b)</strong> When Boxing Day falls on a Saturday or Sunday, a holiday in lieu thereof shall be observed on 28 December.</p><p><strong>(c)</strong> When New Year’s Day falls on a Saturday or Sunday a holiday in lieu thereof shall be observed on the next Monday.</p><p><strong>(d)</strong> When Australia Day falls on a Saturday or Sunday a holiday in lieu thereof shall be observed on the next Monday.</p><p><strong>(e)</strong> When ANZAC Day falls on a Sunday, a holiday in lieu thereof shall be observed on the following Monday.</p><p><strong>(f)</strong> When ANZAC Day falls on Easter Monday, a holiday in lieu thereof shall be observed on the following Tuesday.</p><p><strong>179.4</strong> Where in the State or Locality, public holidays are declared or prescribed on days other than those set out in clause 179.2 and clause 179.3 above, those days shall constitute additional holidays for the purposes of this Part F.</p><p><strong>179.5</strong> Substitute Days</p><p><strong>(a)</strong> An Employer and Employee may agree to substitute another day for a day that would otherwise be a public holiday under the Act or this Agreement.</p><p><strong>(b)</strong> An Employer and Employee may agree to substitute another part-day for a part- day that would otherwise be a part-day public holiday under the Act or this Agreement.</p><p><strong>(c)</strong> Where an agreement under subclause (a) or (b) is reached, it will be recorded in writing and a copy given to the Employee.</p><p><strong>179.6</strong> Penalty Payments in respect of public holidays</p><p><strong>(a)</strong> An Employee, other than a casual, who performs work (including overtime work) on a public holiday is entitled to be paid:</p><p><strong>(i)</strong> 200% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>) for the time worked on a public holiday Monday to Friday; or</p><p><strong>(ii)</strong> 250% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>) for the time worked on a public holiday on a Saturday or Sunday (which is inclusive of the rates for Weekend Work).</p><p><strong>(b)</strong> A Casual Employee who performs work (including overtime work) on a public holiday will be entitled to be paid 175% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>) for the time worked on a public holiday inclusive of the casual loading.</p><p><strong>179.7</strong> Public Holiday not required to work Where a public holiday occurs on a day that a part-time or full-time Employee would normally work, but the Employee is not required by the Employer to work on that day, the</p><p>Employee will be paid an amount equal to the Employee&#39;s ordinary rate of pay for the hours the Employee would normally have worked on that day.</p><p><strong>179.8</strong> Public Holidays occurring on rostered day off If the public holidays fall on the Employee’s rostered day off, they shall be entitled to one and one half times the payment for their ordinary day.</p><p><strong>179.9</strong> Public holidays and Accrued Days Off Where an Employee’s accrued day off falls on a public holiday, another day shall be determined by the Employer to be taken in lieu thereof, within the same 4-week cycle (where practicable).</p><p><strong>179.10</strong> Public holidays and part-time Employees</p><p><strong>(a)</strong> Subject to clause 179.10(b), a regular part-time Employee who is not ordinarily required to work on the day on which a public holiday is observed shall not be entitled to payment for such public holiday unless they are required to work on that day.</p><p><strong>(b)</strong> In determining whether a part-time Employee who works a rotating roster is entitled to receive the &#39;rostered off’ Agreement benefits for a particular public holiday not worked, the Employer shall review the roster pattern of the individual over the preceding six months. If the rosters show that the Employee has worked 50% or more of the days on which a particular public holiday falls, the Employee shall be entitled to receive the ‘rostered off&#39; benefit for that public holiday.</p><p>EDUCATION AND PROFESSIONAL DEVELOPMENT</p><p>Plain language terms: public holiday pay, holiday pay, PH pay, penalty rates holidays.</p>',56)])])}const c=o(n,[["render",s]]);export{u as __pageData,c as default};
